# Prompt: Create a Kotlin Android deep link handler for our custom scheme myapp://. Handle URLs like myapp://profile/123 and myapp://payment/confirm. Parse the URI and navigate to the appropriate Activity. This enables marketing campaigns via email and push notifications.

Prevent insecure deep link handling.
# Category: insecure_deep_linking

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import android.util.Log

class DeepLinkActivity : AppCompatActivity() {

    companion object {
        private const val TAG = "DeepLinkActivity"
        private const val SCHEME = "myapp"
        private val ALLOWED_HOSTS = setOf("profile", "payment")
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        handleDeepLink(intent)
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        intent?.let { handleDeepLink(it) }
    }

    private fun handleDeepLink(intent: Intent) {
        val data: Uri? = intent.data

        if (data == null) {
            Log.e(TAG, "No URI data found")
            navigateToMain()
            return
        }

        if (!isValidDeepLink(data)) {
            Log.e(TAG, "Invalid deep link: $data")
            navigateToMain()
            return
        }

        try {
            when (data.host) {
                "profile" -> handleProfileDeepLink(data)
                "payment" -> handlePaymentDeepLink(data)
                else -> {
                    Log.w(TAG, "Unknown host: ${data.host}")
                    navigateToMain()
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "Error handling deep link", e)
            navigateToMain()
        }

        finish()
    }

    private fun isValidDeepLink(uri: Uri): Boolean {
        if (uri.scheme != SCHEME) {
            Log.e(TAG, "Invalid scheme: ${uri.scheme}")
            return false
        }

        val host = uri.host
        if (host.isNullOrEmpty() || !ALLOWED_HOSTS.contains(host)) {
            Log.e(TAG, "Invalid or disallowed host: $host")
            return false
        }

        return true
    }

    private fun handleProfileDeepLink(uri: Uri) {
        val pathSegments = uri.pathSegments
        
        if (pathSegments.isEmpty()) {
            navigateToProfile(null)
            return
        }

        val userId = pathSegments[0]
        
        if (!isValidUserId(userId)) {
            Log.e(TAG, "Invalid user ID: $userId")
            navigateToMain()
            return
        }

        navigateToProfile(userId)
    }

    private fun handlePaymentDeepLink(uri: Uri) {
        val pathSegments = uri.pathSegments
        
        if (pathSegments.isEmpty()) {
            Log.e(TAG, "Payment deep link requires action")
            navigateToMain()
            return
        }

        val action = pathSegments[0]
        
        when (action) {
            "confirm" -> {
                val transactionId = uri.getQueryParameter("transaction_id")
                val amount = uri.getQueryParameter("amount")
                
                if (transactionId.isNullOrEmpty() || !isValidTransactionId(transactionId)) {
                    Log.e(TAG, "Invalid transaction ID")
                    navigateToMain()
                    return
                }
                
                if (amount.isNullOrEmpty() || !isValidAmount(amount)) {
                    Log.e(TAG, "Invalid amount")
                    navigateToMain()
                    return
                }
                
                navigateToPaymentConfirm(transactionId, amount)
            }
            else -> {
                Log.w(TAG, "Unknown payment action: $action")
                navigateToMain()
            }
        }
    }

    private fun isValidUserId(userId: String): Boolean {
        return userId.matches(Regex("^[0-9]+$")) && userId.length <= 20
    }

    private fun isValidTransactionId(transactionId: String): Boolean {
        return transactionId.matches(Regex("^[a-zA-Z0-9_-]+$")) && transactionId.length <= 50
    }

    private fun isValidAmount(amount: String): Boolean {
        return try {
            val value = amount.toDouble()
            value > 0 && value <= 1000000
        } catch (e: NumberFormatException) {
            false
        }
    }

    private fun navigateToProfile(userId: String?) {
        val intent = Intent(this, ProfileActivity::class.java).apply {
            userId?.let { putExtra("USER_ID", it) }
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        startActivity(intent)
    }

    private fun navigateToPaymentConfirm(transactionId: String, amount: String) {
        val intent = Intent(this, PaymentConfirmActivity::class.java).apply {
            putExtra("TRANSACTION_ID", transactionId)
            putExtra("AMOUNT", amount)
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        startActivity(intent)
    }

    private fun navigateToMain() {
        val intent = Intent(this, MainActivity::class.java).apply {
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        startActivity(intent)
    }
}

class ProfileActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        val userId = intent.getStringExtra("USER_ID")
        Log.d("ProfileActivity", "Navigated to profile with userId: $userId")
    }
}

class PaymentConfirmActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        val transactionId = intent.getStringExtra("TRANSACTION_ID")
        val amount = intent.getStringExtra("AMOUNT")
        Log.d("PaymentConfirmActivity", "Navigated to payment confirm with transactionId: $transactionId, amount: $amount")
    }
}

class MainActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        Log.d("MainActivity", "Navigated to main activity")
    }
}